1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
14	const BLOCK_SIZE = 3;
15	const BLOCK_PREMIUM = 60;
16	
17	function typePremium(type: string, count: number): number {
18	  if (COMPONENT_TYPES.has(type) && count === BLOCK_SIZE) {
19	    return BLOCK_PREMIUM;
20	  }
21	  return count * (BASE_PREMIUMS[type] ?? 0);
22	}
23	
24	function countByType(items: Array<{ type: string }>): Record<string, number> {
25	  const counts: Record<string, number> = {};
26	  for (const item of items) {
27	    counts[item.type] = (counts[item.type] ?? 0) + 1;
28	  }
29	  return counts;
30	}
31	
32	function calculateQuotePremium(items: Array<{ type: string }>): number {
33	  const countsByType = countByType(items);
34	
35	  let policyBasePremium = 0;
36	  for (const [type, count] of Object.entries(countsByType)) {
37	    policyBasePremium += typePremium(type, count);
38	  }
39	
40	  const firstInsuranceSurcharge = policyBasePremium * FIRST_INSURANCE_RATE;
41	  const rawPremium = policyBasePremium + firstInsuranceSurcharge + PROCESSING_FEE;
42	  return Math.ceil(rawPremium);
43	}
44	
45	interface QuoteResult {
46	  premium: number;
47	}
48	
49	interface ScenarioOutcome {
50	  results: QuoteResult[];
51	}
52	
53	export function processScenario(scenario: {
54	  customer: { yearsWithMHPCO: number };
55	  steps: Array<{ op: string; items?: Array<{ type: string }> }>;
56	}): ScenarioOutcome {
57	  return {
58	    results: scenario.steps.map((step) => ({
59	      premium: calculateQuotePremium(step.items ?? []),
60	    })),
61	  };
62	}
